import{_ as e,o as t,c as r,ag as n}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"申根签证全攻略","description":"申根签证申请流程、材料清单和面签技巧","frontmatter":{"title":"申根签证全攻略","description":"申根签证申请流程、材料清单和面签技巧"},"headers":[],"relativePath":"knowledge/visa/schengen.md","filePath":"knowledge/visa/schengen.md","lastUpdated":null}'),o={name:"knowledge/visa/schengen.md"};function i(l,a,s,h,d,c){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="申根签证全攻略" tabindex="-1">申根签证全攻略 <a class="header-anchor" href="#申根签证全攻略" aria-label="Permalink to &quot;申根签证全攻略&quot;">​</a></h1><h2 id="申根签证简介" tabindex="-1">申根签证简介 <a class="header-anchor" href="#申根签证简介" aria-label="Permalink to &quot;申根签证简介&quot;">​</a></h2><p>申根签证允许持有人在申根区内自由旅行，覆盖27个欧洲国家。一次申请即可畅游多国，是欧洲旅行的必备签证。</p><h2 id="申请材料清单" tabindex="-1">申请材料清单 <a class="header-anchor" href="#申请材料清单" aria-label="Permalink to &quot;申请材料清单&quot;">​</a></h2><p>核心材料包括：护照、申请表、照片、旅行保险、行程单、酒店预订、机票订单、银行流水和在职证明等。</p><h2 id="申请流程" tabindex="-1">申请流程 <a class="header-anchor" href="#申请流程" aria-label="Permalink to &quot;申请流程&quot;">​</a></h2><p>建议提前3个月申请。流程为：确定主申国家 → 填写申请表 → 预约递交时间 → 递交材料 → 等待审核（通常15天内）。</p><h2 id="面签技巧" tabindex="-1">面签技巧 <a class="header-anchor" href="#面签技巧" aria-label="Permalink to &quot;面签技巧&quot;">​</a></h2><p>面签时需如实回答行程相关的问题。准备好详细的行程计划、充足的资金证明，并展示明确的回国意愿。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p>拒签原因通常包括材料不全、行程不合理、资金不足或有移民倾向。被拒后可以申诉或重新申请。</p>',11)])])}const u=e(o,[["render",i]]);export{_ as __pageData,u as default};
